import React, {useState, useEffect} from "react";
import axios from 'axios';
import "./uploadposterCSS.css";
import Navbaremployee from "./upperlistemployee";
import Cookies from "universal-cookie";

export const UploadPoster = () => {
    const [search, setSearch] = useState('');
    const cookies=new Cookies();
    
    useEffect(() => {
        cookies.set('search',search,{path:'/'});
        console.log(cookies)
    },[search])

    const [imageUrl, setImageUrl] = useState('');
    const [imageSrc, setImageSrc] = useState('');
    const [error, setError] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();

        try {
        const response = await axios.get(imageUrl);
            setImageSrc(response.config.url);
            setError('');
        } catch (err) {
            setError('无法加载图像，请检查输入的URL。');
            setImageSrc('');
        }
    };

    return(
        <>
            {/* <Navbaremployee setSearch={setSearch}/> */}
            {/* https://ottaster.com/js-upload-file/ */}
            <form onSubmit={handleSubmit}>
                <label>
                输入图像URL：
                <input
                    type="text"
                    value={imageUrl}
                    onChange={(e) => setImageUrl(e.target.value)}
                />
                </label>
                <button type="submit">提交</button>
            </form>

            {error && <p style={{ color: 'red' }}>{error}</p>}

            {imageSrc && (
                <div>
                <h2>显示图像：</h2>
                <img src={imageSrc} alt="用户输入的图像" style={{ maxWidth: '100%' }} />
                </div>
            )}
        </>
    );
};
export default UploadPoster;
